		final int codePoint = Character.codePointAt(cs, offset);

		// Check if this code point (either BMP char or supplementary char) matches any in searchChars
		for (int j = 0; j < searchChars.length; j++) {
			char searchChar = searchChars[j];

			// If searchChar is part of a supplementary character, we need to check if the full code point matches
